        [itemHeight]="itemHeight"
        [maxPanelHeight]="maxPanelHeight"
      />
      <p style="margin-top: var(--pui-space-sm); color: var(--pui-muted); font-size: var(--pui-font-size-sm);">
        Selected: {{ selected | json }}
      </p>
    `,
  }),
};

